// Group by token address and spender
const approvalMap = new Map<string, { token: string; spender: string; lastValue: bigint }>()

for (const event of approvalEvents) {
  const tokenAddress = event.address
  const spender = event.args.spender
  const value = event.args.value

  if (!spender || value === undefined) continue

  const key = `${tokenAddress.toLowerCase()}-${spender.toLowerCase()}`

  // Keep the most recent approval value
  if (!approvalMap.has(key) || event.blockNumber > (approvalMap.get(key) as any).blockNumber) {
    approvalMap.set(key, {
      token: tokenAddress,
      spender,
      lastValue: value,
    })
  }
}

